import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Signup() {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [loading, setLoading] = useState(false); // Loading state add ki hai
  const navigate = useNavigate();

  const handleSignup = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      // 1. Zaroori: Check karein ki Backend terminal mein URL http://127.0.0.1:8000 hi hai
      const response = await axios.post('http://127.0.0.1:8000/api/register', {
        username: formData.username,
        email: formData.email, 
        password: formData.password
      });

      if (response.status === 200 || response.status === 201) {
        alert("Registration Successful!"); 
        navigate('/login');
      }

    } catch (err) {
      if (err.response) {
        // Backend se response aaya (422, 400, 500)
        console.error("Backend Error Data:", err.response.data);
        const detail = err.response.data.detail;
        alert("Error: " + (typeof detail === 'object' ? JSON.stringify(detail) : detail));
      } else if (err.request) {
        // Request gayi par response nahi aaya (Network Error)
        alert("Connectivity Issue: Backend server (Uvicorn) se connection nahi ban raha. Check karein ki server chalu hai.");
      } else {
        alert("Error: " + err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="signup-page" style={{ padding: '50px', textAlign: 'center' }}>
      <div className="form-container" style={{ display: 'inline-block', background: '#f9f9f9', padding: '30px', borderRadius: '10px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)' }}>
        <h2>Naya Account Banayein</h2>
        <form onSubmit={handleSignup}>
          <input 
            type="text" 
            placeholder="Username" 
            value={formData.username}
            onChange={(e) => setFormData({...formData, username: e.target.value})} 
            required 
            style={{padding: '10px', margin: '8px', width: '280px', borderRadius: '5px', border: '1px solid #ddd'}} 
          /><br/>

          <input 
            type="email" 
            placeholder="Email" 
            value={formData.email}
            onChange={(e) => setFormData({...formData, email: e.target.value})} 
            required 
            style={{padding: '10px', margin: '8px', width: '280px', borderRadius: '5px', border: '1px solid #ddd'}} 
          /><br/>

          <input 
            type="password" 
            placeholder="Password" 
            value={formData.password}
            onChange={(e) => setFormData({...formData, password: e.target.value})} 
            required 
            style={{padding: '10px', margin: '8px', width: '280px', borderRadius: '5px', border: '1px solid #ddd'}} 
          /><br/>

          <button 
            type="submit" 
            disabled={loading}
            style={{ 
              backgroundColor: loading ? '#bdc3c7' : '#3498db', 
              color: 'white', 
              padding: '12px 30px', 
              border: 'none', 
              borderRadius: '5px',
              cursor: loading ? 'not-allowed' : 'pointer', 
              marginTop: '15px',
              fontSize: '16px',
              fontWeight: 'bold'
            }}
          >
            {loading ? "Registering..." : "Register Now"}
          </button>
        </form>

        <p style={{ marginTop: '20px', fontSize: '14px' }}>
          Pehle se account hai? <span style={{ color: '#3498db', cursor: 'pointer', fontWeight: 'bold' }} onClick={() => navigate('/login')}>Login karein</span>
        </p>
      </div>
    </div>
  );
}

export default Signup;
